mapper.select:
SELECT FROM ( SELECT er.*, ROW_NUMBER() OVER (PARTITION BY currency_code ORDER BY announced_at DESC) rn FROM exchange_rates er WHERE currency_code IN
#{code}
) WHERE rn = 1

SELECT 
FROM exchange_rates
WHERE currency_code = #{currencyCode}
  AND announced_at = (
      SELECT MAX(announced_at)
      FROM exchange_rates
      WHERE currency_code = #{currencyCode}
        AND TRUNC(announced_at) <= TO_DATE(#{date}, 'YYYY-MM-DD')
  )
